    pub defer_count: u64,
    /// Total deny decisions
    pub deny_count: u64,
}

impl Default for FabricState {
    fn default() -> Self {
        Self {
            tick: 0,
            syndromes_ingested: 0,
            active_tiles: 0,
            last_decision: GateDecision::Cautious,
            quarantine_mask: RegionMask::none(),
