                value: false,
            },
        ],
        code_distance: 3,
        num_rounds: 1,
    };
    let corr_low = decoder.decode(&syndrome_low);

    // Many defects -> lower confidence.
    let syndrome_high = SyndromeData {
        stabilizers: vec![
