        let lines = gate_lines(&qasm);
        assert_eq!(lines.len(), 4);
        assert_eq!(lines[0], "h q[0];");
        assert_eq!(lines[1], "cx q[0], q[1];");
        assert_eq!(lines[2], "c[0] = measure q[0];");
        assert_eq!(lines[3], "c[1] = measure q[1];");
    }

