            BasisGateSet::IonQAria,
            BasisGateSet::RigettiAspen,
            BasisGateSet::Universal,
        ];
        for (i, a) in variants.iter().enumerate() {
            for (j, b) in variants.iter().enumerate() {
                if i == j {
                    assert_eq!(a, b);
                } else {
                    assert_ne!(a, b);
                }
            }
        }
    }
