        let search = QuantumCollapseSearch::new(vec![vec![1.0], vec![2.0], vec![3.0]]);
        assert_eq!(search.num_qubits, 2);
        assert_eq!(search.candidates.len(), 4);
        assert_eq!(search.num_real, 3);
    }

