            a.set(i, true);
        }
        for i in (256..768).step_by(2) {
            bb.set(i, true);
        }

        b.iter(|| {
            let result = a.xor(&bb);
            let count = result.popcount();
            black_box(count);
        });
    });

    // TileReport copy should be allocation-free
    group.bench_function("tile_report_copy_no_alloc", |b| {
        let mut report = TileReport::new(1);
