                    black_box(report)
                });
            },
        );

        // Filter pipeline evaluation
        group.bench_with_input(
            BenchmarkId::new("filter_pipeline", format!("q{}", qubit_count)),
            qubit_count,
            |b, &qubits| {
                let pipeline = create_scaled_filter_pipeline(qubits);
                let state = SystemState::new(qubits);

                b.iter(|| {
