                let round = create_syndrome_round(round_id, 64, 0.1);
                buffer.push(round);
                round_id += 1;
            }
            black_box(&buffer);
        });
    });

    // Large batch ingestion (10000 rounds)
    group.throughput(Throughput::Elements(10_000));
