            })
            .collect();

        let decision = tilezero.merge_reports(reports);

        if cut_value < 5.0 {
            assert_eq!(decision, GateDecision::Deny);
        } else {
            assert_eq!(decision, GateDecision::Permit);
        }
    }

    assert_eq!(tilezero.receipt_log.len(), 1_000);
