        let mut transitions = 0;

        for i in 0..1_000 {
            // Vary parameters to cause state changes
            let cut_value = 5.0 + (i as f64).sin() * 10.0;
            let shift_score = 0.3 + (i as f64).cos().abs() * 0.4;

            let reports: Vec<TileReport> = (1..=5)
                .map(|j| {
