                })
                .collect();

            let decision = tilezero.merge_reports(reports);

            if decision != last_decision {
                transitions += 1;
                last_decision = decision;
            }
        }

        // Should have some state transitions
        println!("Decision state transitions: {}", transitions);
        assert!(transitions > 0);
