                cycle * 50 + i,
                cycle * 50 + i,
                (cycle * 50 + i) * 1_000,
                DetectorBitmap::new(64),
                0,
            );
            buffer.push(round);
        }

        if cycle % 10 == 0 {
            buffer.clear();
        }
    }

    // Buffer should be valid
    assert!(buffer.len() <= 100);
}

