mod syndrome_buffer_tests {
    use super::*;

    #[test]

fn test_buffer_creation() {
    let buffer = SyndromeBuffer::new(100);

    assert_eq!(buffer.capacity(), 100);
    assert_eq!(buffer.len(), 0);
    assert!(buffer.is_empty());
