fn test_buffer_get_by_round_id() {
    let mut buffer = SyndromeBuffer::new(100);

    for i in 0..50 {
        let mut detectors = DetectorBitmap::new(64);
        detectors.set(i as usize % 64, true);
        let round = SyndromeRound::new(i, i, i * 1_000, detectors, 0);
        buffer.push(round);
