    fn test_delta_same_round() {
        let detectors = DetectorBitmap::new(64);
        let round = SyndromeRound::new(1, 100, 1_000, detectors, 0);

        let delta = SyndromeDelta::compute(&round, &round);

        assert!(delta.is_quiet());
        assert_eq!(delta.span(), 0);
