                    let mut state = QuantumState::new(n).unwrap();
                    for q in 0..n {
                        state.apply_gate(&Gate::H(q)).unwrap();
                    }
                    // Phase separation: linear chain
                    for q in 0..n.saturating_sub(1) {
                        state.apply_gate(&Gate::Rzz(q, q + 1, 0.5)).unwrap();
