#[test]
fn test_rx_pi_is_x() {
    // Rx(pi)|0> = -i|1> (probability of |1> should be 1)
    let mut state = QuantumState::new(1).unwrap();
    state
        .apply_gate(&Gate::Rx(0, std::f64::consts::PI))
