    state.apply_gate(&Gate::H(0)).unwrap();
    state.apply_gate(&Gate::S(0)).unwrap();
    let sv = state.state_vector();
    let s = std::f64::consts::FRAC_1_SQRT_2;
    assert!(approx_eq(sv[0].re, s));
    assert!(approx_eq(sv[0].im, 0.0));
