#[test]
fn test_complex_unit_norm() {
    // e^{i*pi/4} has norm 1
    let angle = std::f64::consts::FRAC_PI_4;
    let z = Complex {
        re: angle.cos(),
        im: angle.sin(),
    };
    assert!(approx_eq(z.norm(), 1.0));
}

