}

#[test]
fn test_hamiltonian_multiple_terms() {
    // H = 0.5*Z0 + 0.3*Z1 + 0.2*Z0Z1
    let h = Hamiltonian {
        terms: vec![
            (
                0.5,
                PauliString {
                    ops: vec![(0, PauliOp::Z)],
                },
            ),
            (
                0.3,
                PauliString {
                    ops: vec![(1, PauliOp::Z)],
                },
            ),
            (
                0.2,
                PauliString {
                    ops: vec![(0, PauliOp::Z), (1, PauliOp::Z)],
                },
            ),
        ],
        num_qubits: 2,
    };
    assert_eq!(h.terms.len(), 3);
