    let h = Hamiltonian {
        terms: vec![
            (
                -0.5,
                PauliString {
                    ops: vec![(0, PauliOp::Z)],
                },
            ),
            (
                1.2,
                PauliString {
                    ops: vec![(0, PauliOp::X), (1, PauliOp::X)],
                },
            ),
        ],
        num_qubits: 2,
    };
    assert!(approx_eq(h.terms[0].0, -0.5));
    assert!(approx_eq(h.terms[1].0, 1.2));
}

#[test]
fn test_hamiltonian_empty() {
