        num_qubits: 0,
    };
    assert_eq!(h.terms.len(), 0);
}

#[test]

fn test_hamiltonian_ising_model() {
    // Simple 3-qubit Ising: H = -J * sum(Z_i Z_{i+1}) - h * sum(X_i)
    let j = 1.0_f64;
    let field = 0.5_f64;
    let h = Hamiltonian {
        terms: vec![
            (
                -j,
                PauliString {
                    ops: vec![(0, PauliOp::Z), (1, PauliOp::Z)],
                },
            ),
            (
                -j,
                PauliString {
                    ops: vec![(1, PauliOp::Z), (2, PauliOp::Z)],
                },
            ),
            (
                -field,
                PauliString {
                    ops: vec![(0, PauliOp::X)],
                },
            ),
            (
                -field,
                PauliString {
                    ops: vec![(1, PauliOp::X)],
                },
            ),
            (
                -field,
                PauliString {
                    ops: vec![(2, PauliOp::X)],
                },
            ),
        ],
        num_qubits: 3,
    };
    assert_eq!(h.terms.len(), 5);
    assert_eq!(h.num_qubits, 3);
}

