    let candidates = vec![
        vec![1.0, 0.0, 0.0],
        vec![0.0, 1.0, 0.0],
        vec![0.0, 0.0, 1.0],
    ];
    let search = QuantumCollapseSearch::new(candidates);
    let dist = search.search_distribution(&[1.0, 0.0, 0.0], 3, 200, 42);
