            &format!("p{}", i),
            action.clone(),
            1.0,
            true,
        ));
    }
    let pure_prob = pure.decide()[0].probability;

    // Support with opposition
    let mut mixed = SwarmInterference::new();
    for i in 0..3 {
        mixed.contribute(AgentContribution::new(
            &format!("p{}", i),
            action.clone(),
            1.0,
